INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-6f0ba476-moex-00135', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲夫乙妻育有一女丙。甲乙離婚後，乙擔任10歲丙之親權人。乙將丙出養於丁。下列關於該收 養效力之敘述，何者正確？', '["因丙為未成年人，乙代丙為收養契約之意思表示，有效", "收養未得甲之同意，原則上無效", "收養契約當事人為丙與丁，丁妻戊未共同為之，戊不得撤銷", "收養未具書面但已向法院聲請認可，有效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00136', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲男乙女為夫妻，有一成年子丙。丁女已離婚，有一子戊。嗣後，丙、丁結婚。甲、戊之關係為何？', '["旁系姻親", "旁系血親", "直系姻親", "無親屬關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00137', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲男及乙女分割丙父之遺產，甲分到一棟價值新臺幣（下同）500萬元之房子，乙分到丙對叔叔 丁之500萬元債權。乙分到此債權時，丁只付300萬元，即因破產再也無法返還乙200萬元。乙 就該丁未能償還之200萬元，得向甲請求多少金額？', '["50萬元", "100萬元", "200萬元", "乙不得向甲請求任何金額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00138', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於繼承人喪失繼承權之敘述，何者錯誤？', '["繼承人隱匿遺產情節重大者，其繼承權喪失", "繼承人以詐欺或脅迫，使被繼承人為關於繼承之遺囑者，其繼承權喪失", "繼承人偽造、變造、隱匿或湮滅被繼承人關於繼承之遺囑者，其繼承權喪失", "繼承人以詐欺或脅迫妨害被繼承人撤回其遺囑者，其繼承權喪失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00139', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲喪偶有乙、丙、丁三子。甲於乙、丙、丁結婚時，各贈與新臺幣（下同）50萬元。甲死亡時， 留有遺產350萬元，負債50萬元。甲生前立有遺囑，遺贈戊300萬元。戊最多得受多少金額之 遺贈？', '["200萬元", "225萬元", "250萬元", "300萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00140', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'essay', '土地增值稅、地價稅、房屋稅、使用牌照稅、契稅與印花稅為財政收支
劃分法所明訂之直轄市及縣（市）稅，屬於地方政府重要財源。然租稅
之課徵，如逾核課期間，便不得再予補稅處罰；是以，核課期間之計算
至關重要。請根據稅捐稽徵法規定，詳細說明上述各種直轄市及縣（市）
稅核課期間起算之規定。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "e76084a7e056", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00141', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'essay', '為防止透過移轉型態避稅，我國自 110 年 7月 1日起，施行房地合一所
得稅制度精進作法，即一般所稱之「房地合一稅制 2.0」。新制擴大房地
合一的課稅範圍，除原有之個人及營利事業交易於 105 年 1月 1日以後
取得之房屋、土地，以及個人於105 年 1 月 1日以後取得以設定地上權
方式之房屋使用權外，增列之課稅標的為何？又在新制下，房地交易所
產生之土地增值稅，是否能於計算課稅所得時減除，請論述之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "e76084a7e056", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00142', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法規定，有關稅捐核課期間屆滿時，其時效不完成之敘述，下列何者正確？', '["納稅義務人對核定稅捐處分提起行政救濟尚未終結者，自核定稅捐處分經訴願或行政訴訟撤銷 須另為處分確定之日起算一年內", "因天災、事變或不可抗力之事由致未能作成核定稅捐處分者，自妨礙事由消滅之日起算一年內", "納稅義務人對核定稅捐處分提起行政救濟尚未終結者，自核課期間屆滿之日起算一年內", "納稅義務人對核定稅捐處分提起行政救濟尚未終結者，自徵收期間屆滿之日起算一年內"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "e76084a7e056", "answer_pdf_sha1": "6440ab763a6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00143', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '經合法送達之繳款書所載應納稅款為30萬元，繳納期限為113年3月10日，納稅義務人逾期未 繳納稅款，且未依規定申請復查，經稽徵機關移送行政執行分署強制執行，行政執行分署於113 年6月10日開始執行，其執行期間，自徵收期間屆滿之翌日起算，最長為幾年？', '["5年", "10年", "15年", "20年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "e76084a7e056", "answer_pdf_sha1": "6440ab763a6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00144', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法第26條之1規定，納稅義務人有下列何種情形，不能於法定期間內繳清稅捐者，', '["依法應繳納所得稅，因客觀事實發生財 務困難", "經稅捐稽徵機關查獲應補徵鉅額稅捐", "依法應繳納貨物稅，因客觀事實發生財務困 難", "依法應繳納營業稅，因客觀事實發生財務困難"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "e76084a7e056", "answer_pdf_sha1": "6440ab763a6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
